mapper.select:
SELECT
    hi.collected_at as timestamp,
    hi.avg_idx_hit_ratio as cache_hit_ratio
FROM hot_index_agg hi
INNER JOIN database d ON hi.database_id = d.database_id
WHERE d.instance_id = #{instanceId}
  AND hi.database_id = #{databaseId}
  AND hi.collected_at BETWEEN #{startTime} AND #{endTime}
ORDER BY hi.collected_at

SELECT
    hi.collected_at as timestamp,
    hi.total_idx_tup_read as idx_tup_read,
    hi.total_idx_tup_fetch as idx_tup_fetch
FROM hot_index_agg hi
INNER JOIN database d ON hi.database_id = d.database_id
WHERE d.instance_id = #{instanceId}
  AND hi.database_id = #{databaseId}
  AND hi.collected_at BETWEEN #{startTime} AND #{endTime}
ORDER BY hi.collected_at

SELECT
    hi.collected_at as timestamp,
    hi.avg_scan_time_ms
FROM hot_index_agg hi
INNER JOIN database d ON hi.database_id = d.database_id
WHERE d.instance_id = #{instanceId}
  AND hi.database_id = #{databaseId}
  AND hi.collected_at BETWEEN #{startTime} AND #{endTime}
ORDER BY hi.collected_at

SELECT hi.hot_index_raw_id, hi.schema_name, hi.table_name, hi.index_name, hi.index_type, hi.index_size, hi.idx_scan, hi.idx_tup_read, hi.idx_tup_fetch, hi.idx_blks_read, hi.idx_blks_hit, hi.bloat_percent, hi.avg_scan_time_ms, hi.last_idx_scan, CASE WHEN hi.idx_scan = 0 THEN '미사용' WHEN hi.bloat_percent >= 30 THEN 'bloat' WHEN (CASE WHEN (hi.idx_blks_read + hi.idx_blks_hit) = 0 THEN 0 ELSE (hi.idx_blks_hit * 100.0 / (hi.idx_blks_read + hi.idx_blks_hit)) END) < 85 OR hi.avg_scan_time_ms > 10 THEN '비효율' ELSE '정상' END as status FROM hot_index_raw hi INNER JOIN database d ON hi.database_id = d.database_id WHERE d.instance_id = #{instanceId} AND hi.database_id = #{databaseId} AND hi.collected_at BETWEEN #{startTime} AND #{endTime}
AND CASE WHEN hi.idx_scan = 0 THEN '미사용' WHEN hi.bloat_percent >= 30 THEN 'bloat' WHEN (CASE WHEN (hi.idx_blks_read + hi.idx_blks_hit) = 0 THEN 0 ELSE (hi.idx_blks_hit * 100.0 / (hi.idx_blks_read + hi.idx_blks_hit)) END) < 85 OR hi.avg_scan_time_ms > 10 THEN '비효율' ELSE '정상' END IN
#{status}
ORDER BY hi.collected_at DESC
